interface SummaryGenerationParams {
  conversationId: string;
  userId: string;
  maestroId: string;
  sessionId?: string;
}

async function generateAndSaveConversationSummary(params: SummaryGenerationParams): Promise<void> {
  // 1. Fetch conversation with messages
  const conversation = await prisma.conversation.findUnique({
    where: { id: params.conversationId },
    include: { messages: { orderBy: { createdAt: 'asc' } } }
  });

  if (!conversation || conversation.messages.length < 5) {
    return; // Skip short conversations
  }

  // 2. Generate summary using existing summarize.ts functions
  const messages = conversation.messages.map(m => ({
    role: m.role,
    content: m.content
  }));

  const [summary, keyFacts, topics, learnings] = await Promise.all([
    generateConversationSummary(messages),
    extractKeyFacts(messages),
    extractTopics(messages),
    extractLearnings(messages, params.maestroId),
  ]);

  // 3. Save to Conversation
  await prisma.conversation.update({
    where: { id: params.conversationId },
    data: {
      summary,
      keyFacts: JSON.stringify(keyFacts),
      topics: JSON.stringify(topics),
      isActive: false,
    }
  });

  // 4. Save learnings
  for (const learning of learnings) {
    await prisma.learning.upsert({
      where: {
        userId_category_insight: {
          userId: params.userId,
          category: learning.category,
          insight: learning.insight.slice(0, 50), // Key for dedup
        }
      },
      update: {
        confidence: { increment: 0.1 },
        occurrences: { increment: 1 },
      },
      create: {
        userId: params.userId,
        category: learning.category,
        insight: learning.insight,
        maestroId: params.maestroId,
        confidence: learning.confidence,
      }
    });
  }
}
```

