class ConversationInactivityMonitor {
  private timers: Map<string, NodeJS.Timeout> = new Map();

  startTracking(conversationId: string, maestroId: string, config: InactivityConfig) {
    this.resetTimer(conversationId, maestroId, config);
  }

  resetTimer(conversationId: string, maestroId: string, config: InactivityConfig) {
    // Clear existing timer
    const existing = this.timers.get(conversationId);
    if (existing) clearTimeout(existing);

    // Set new timer
    const timer = setTimeout(async () => {
      await config.onTimeout(conversationId, maestroId);
      this.timers.delete(conversationId);
    }, config.timeoutMs);

    this.timers.set(conversationId, timer);
  }

  stopTracking(conversationId: string) {
    const timer = this.timers.get(conversationId);
    if (timer) {
      clearTimeout(timer);
      this.timers.delete(conversationId);
    }
  }
}
