     1→/**
     2→ * ConvergioEdu Conversation Flow Store
     3→ *
     4→ * Manages the state of the conversation-first interface:
     5→ * - Current active character (Coach, Maestro, Buddy)
     6→ * - SEPARATE conversations per character (#33)
     7→ * - Character routing and handoffs
     8→ *
     9→ * Part of I-01: Conversation-First Main Flow
    10→ * Related: #24 MirrorBuddy Issue, #33 Separate Conversations, ManifestoEdu.md
    11→ */
    12→
    13→import { create } from 'zustand';
    14→import type { CharacterType, ExtendedStudentProfile } from '@/types';
    15→import type { MaestroFull } from '@/data/maestri';
    16→import type { SupportTeacher } from '@/types';
    17→import type { BuddyProfile } from '@/types';
    18→import {
    19→  routeToCharacter,
    20→  getCharacterGreeting as _getCharacterGreeting,
    21→  getCharacterSystemPrompt as _getCharacterSystemPrompt,
    22→  type RoutingResult,
    23→} from '@/lib/ai/character-router';
    24→import { getDefaultSupportTeacher, getSupportTeacherById } from '@/data/support-teachers';
    25→import { getBuddyForStudent } from '@/lib/ai/character-router';
    26→import { getBuddyById, type BuddyId } from '@/data/buddy-profiles';
    27→import { getMaestroById } from '@/data/maestri';
    28→
    29→// ============================================================================
    30→// TYPES
    31→// ============================================================================
    32→
    33→/**
    34→ * Active character in the conversation.
    35→ */
    36→export interface ActiveCharacter {
    37→  type: CharacterType;
    38→  id: string;
    39→  name: string;
    40→  character: MaestroFull | SupportTeacher | BuddyProfile;
    41→  greeting: string;
    42→  systemPrompt: string;
    43→  color: string;
    44→  voice: string;
    45→  voiceInstructions: string;
    46→  subtitle?: string;
    47→}
    48→
    49→/**
    50→ * A message in the conversation flow.
    51→ */
    52→export interface FlowMessage {
    53→  id: string;
    54→  role: 'user' | 'assistant' | 'system';
    55→  content: string;
    56→  timestamp: Date;
    57→  characterId?: string;
    58→  characterType?: CharacterType;
    59→  /** If this message triggered a character switch */
    60→  switchedTo?: {
    61→    type: CharacterType;
    62→    id: string;
    63→    reason: string;
    64→  };
    65→}
    66→
    67→/**
    68→ * Stored conversation for a character.
    69→ */
    70→export interface CharacterConversation {
    71→  characterId: string;
    72→  characterType: CharacterType;
    73→  characterName: string;
    74→  messages: FlowMessage[];
    75→  lastMessageAt: Date | null;
    76→  conversationId?: string; // DB conversation ID if synced
    77→}
    78→
    79→/**
    80→ * Handoff suggestion from character routing.
    81→ */
    82→export interface HandoffSuggestion {
    83→  toCharacter: ActiveCharacter;
    84→  reason: string;
    85→  confidence: number;
    86→}
    87→
    88→/**
    89→ * Conversation flow mode.
    90→ */
    91→export type FlowMode = 'text' | 'voice' | 'idle';
    92→
    93→// ============================================================================
    94→// STORE
    95→// ============================================================================
    96→
    97→interface ConversationFlowState {
    98→  // Current state
    99→  mode: FlowMode;
   100→  isActive: boolean;
   101→  activeCharacter: ActiveCharacter | null;
   102→  messages: FlowMessage[]; // Current character's messages (displayed)
   103→  pendingHandoff: HandoffSuggestion | null;
   104→
   105→  // SEPARATE CONVERSATIONS PER CHARACTER (#33)
   106→  conversationsByCharacter: Record<string, CharacterConversation>;
   107→
   108→  // Session tracking
   109→  sessionId: string | null;
   110→  sessionStartedAt: Date | null;
   111→
   112→  // Character history (for back navigation)
   113→  characterHistory: Array<{ type: CharacterType; id: string; timestamp: Date }>;
   114→
   115→  // Actions
   116→  startConversation: (profile: ExtendedStudentProfile) => void;
   117→  endConversation: () => void;
   118→  setMode: (mode: FlowMode) => void;
   119→
   120→  // Message actions
   121→  addMessage: (message: Omit<FlowMessage, 'id' | 'timestamp'>) => void;
   122→  clearMessages: () => void;
   123→
   124→  // Character routing
   125→  routeMessage: (message: string, profile: ExtendedStudentProfile) => RoutingResult;
   126→  switchToCharacter: (
   127→    character: MaestroFull | SupportTeacher | BuddyProfile,
   128→    type: CharacterType,
   129→    profile: ExtendedStudentProfile,
   130→    reason?: string
   131→  ) => void;
   132→  switchToCoach: (profile: ExtendedStudentProfile) => void;
   133→  switchToMaestro: (maestro: MaestroFull, profile: ExtendedStudentProfile) => void;
   134→  switchToBuddy: (profile: ExtendedStudentProfile) => void;
   135→  goBack: (profile: ExtendedStudentProfile) => boolean;
   136→
   137→  // Handoff management
   138→  suggestHandoff: (suggestion: HandoffSuggestion) => void;
   139→  acceptHandoff: (profile: ExtendedStudentProfile) => void;
   140→  dismissHandoff: () => void;
   141→
   142→  // Conversation history
   143→  getConversationForCharacter: (characterId: string) => CharacterConversation | null;
   144→  getAllConversations: () => CharacterConversation[];
   145→
   146→  // Reset
   147→  reset: () => void;
   148→}
   149→
   150→/**
   151→ * Creates an ActiveCharacter from character data.
   152→ */
   153→function createActiveCharacter(
   154→  character: MaestroFull | SupportTeacher | BuddyProfile,
   155→  type: CharacterType,
   156→  profile: ExtendedStudentProfile
   157→): ActiveCharacter {
   158→  let greeting: string;
   159→  let systemPrompt: string;
   160→  let voiceInstructions: string;
   161→
   162→  if (type === 'buddy') {
   163→    const buddy = character as BuddyProfile;
   164→    greeting = buddy.getGreeting(profile);
   165→    systemPrompt = buddy.getSystemPrompt(profile);
   166→    voiceInstructions = buddy.voiceInstructions;
   167→  } else if (type === 'coach') {
   168→    const coach = character as SupportTeacher;
   169→    greeting = coach.greeting;
   170→    systemPrompt = coach.systemPrompt;
   171→    voiceInstructions = coach.voiceInstructions;
   172→  } else {
   173→    const maestro = character as MaestroFull;
   174→    greeting = maestro.greeting;
   175→    systemPrompt = maestro.systemPrompt;
   176→    voiceInstructions = '';
   177→  }
   178→
   179→  return {
   180→    type,
   181→    id: character.id,
   182→    name: character.name,
   183→    character,
   184→    greeting,
   185→    systemPrompt,
   186→    color: character.color,
   187→    voice: 'voice' in character ? character.voice : 'alloy',
   188→    voiceInstructions,
   189→  };
   190→}
   191→
   192→/**
   193→ * Save current messages to character's conversation bucket.
   194→ */
   195→function saveCurrentConversation(
   196→  state: ConversationFlowState
   197→): Record<string, CharacterConversation> {
   198→  if (!state.activeCharacter || state.messages.length === 0) {
   199→    return state.conversationsByCharacter;
   200→  }
   201→
   202→  const characterId = state.activeCharacter.id;
   203→  const existingConvo = state.conversationsByCharacter[characterId];
   204→
   205→  return {
   206→    ...state.conversationsByCharacter,
   207→    [characterId]: {
   208→      characterId,
   209→      characterType: state.activeCharacter.type,
   210→      characterName: state.activeCharacter.name,
   211→      messages: state.messages,
   212→      lastMessageAt: new Date(),
   213→      conversationId: existingConvo?.conversationId,
   214→    },
   215→  };
   216→}
   217→
   218→/**
   219→ * Load messages for a character from their conversation bucket.
   220→ */
   221→function loadConversationMessages(
   222→  conversationsByCharacter: Record<string, CharacterConversation>,
   223→  characterId: string
   224→): FlowMessage[] {
   225→  const convo = conversationsByCharacter[characterId];
   226→  return convo?.messages || [];
   227→}
   228→
   229→export const useConversationFlowStore = create<ConversationFlowState>()(
   230→  (set, get) => ({
   231→      mode: 'idle',
   232→      isActive: false,
   233→      activeCharacter: null,
   234→      messages: [],
   235→      pendingHandoff: null,
   236→      conversationsByCharacter: {},
   237→      sessionId: null,
   238→      sessionStartedAt: null,
   239→      characterHistory: [],
   240→
   241→      startConversation: (profile) => {
   242→        const coach = getDefaultSupportTeacher();
   243→        const activeCharacter = createActiveCharacter(coach, 'coach', profile);
   244→
   245→        // Check if we have existing conversation with this coach
   246→        const state = get();
   247→        const existingMessages = loadConversationMessages(
   248→          state.conversationsByCharacter,
   249→          coach.id
   250→        );
   251→
   252→        // If no existing messages, start with greeting
   253→        const messages: FlowMessage[] =
   254→          existingMessages.length > 0
   255→            ? existingMessages
   256→            : [
   257→                {
   258→                  id: crypto.randomUUID(),
   259→                  role: 'assistant',
   260→                  content: activeCharacter.greeting,
   261→                  timestamp: new Date(),
   262→                  characterId: activeCharacter.id,
   263→                  characterType: 'coach',
   264→                },
   265→              ];
   266→
   267→        set({
   268→          isActive: true,
   269→          mode: 'text',
   270→          activeCharacter,
   271→          messages,
   272→          sessionId: crypto.randomUUID(),
   273→          sessionStartedAt: new Date(),
   274→          characterHistory: [{ type: 'coach', id: coach.id, timestamp: new Date() }],
   275→          pendingHandoff: null,
   276→        });
   277→      },
   278→
   279→      endConversation: () => {
   280→        // Save current conversation before ending
   281→        const state = get();
   282→        const updatedConversations = saveCurrentConversation(state);
   283→
   284→        set({
   285→          isActive: false,
   286→          mode: 'idle',
   287→          activeCharacter: null,
   288→          messages: [],
   289→          pendingHandoff: null,
   290→          sessionId: null,
   291→          sessionStartedAt: null,
   292→          characterHistory: [],
   293→          conversationsByCharacter: updatedConversations,
   294→        });
   295→      },
   296→
   297→      setMode: (mode) => set({ mode }),
   298→
   299→      addMessage: (message) => {
   300→        const state = get();
   301→        const newMessage: FlowMessage = {
   302→          ...message,
   303→          id: crypto.randomUUID(),
   304→          timestamp: new Date(),
   305→          characterId: message.role === 'assistant' ? state.activeCharacter?.id : undefined,
   306→          characterType: message.role === 'assistant' ? state.activeCharacter?.type : undefined,
   307→        };
   308→
   309→        const newMessages = [...state.messages, newMessage];
   310→
   311→        // Also update the conversation bucket
   312→        const characterId = state.activeCharacter?.id;
   313→        let updatedConversations = state.conversationsByCharacter;
   314→
   315→        if (characterId && state.activeCharacter) {
   316→          updatedConversations = {
   317→            ...state.conversationsByCharacter,
   318→            [characterId]: {
   319→              characterId,
   320→              characterType: state.activeCharacter.type,
   321→              characterName: state.activeCharacter.name,
   322→              messages: newMessages,
   323→              lastMessageAt: new Date(),
   324→              conversationId: state.conversationsByCharacter[characterId]?.conversationId,
   325→            },
   326→          };
   327→        }
   328→
   329→        set({
   330→          messages: newMessages,
   331→          conversationsByCharacter: updatedConversations,
   332→        });
   333→      },
   334→
   335→      clearMessages: () => {
   336→        const state = get();
   337→        const characterId = state.activeCharacter?.id;
   338→
   339→        // Also clear from conversation bucket
   340→        if (characterId) {
   341→          const { [characterId]: _, ...rest } = state.conversationsByCharacter;
   342→          set({ messages: [], conversationsByCharacter: rest });
   343→        } else {
   344→          set({ messages: [] });
   345→        }
   346→      },
   347→
   348→      routeMessage: (message, profile) => {
   349→        const state = get();
   350→        return routeToCharacter({
   351→          message,
   352→          studentProfile: profile,
   353→          currentCharacter: state.activeCharacter
   354→            ? { type: state.activeCharacter.type, id: state.activeCharacter.id }
   355→            : undefined,
   356→          preferContinuity: true,
   357→        });
   358→      },
   359→
   360→      switchToCharacter: (character, type, profile, _reason) => {
   361→        const state = get();
   362→
   363→        // 1. Save current conversation to its bucket
   364→        const savedConversations = saveCurrentConversation(state);
   365→
   366→        // 2. Create new active character
   367→        const activeCharacter = createActiveCharacter(character, type, profile);
   368→
   369→        // 3. Load existing messages for new character (or start fresh)
   370→        let messages = loadConversationMessages(savedConversations, character.id);
   371→
   372→        if (messages.length === 0) {
   373→          // No existing conversation - add greeting
   374→          messages = [
   375→            {
   376→              id: crypto.randomUUID(),
   377→              role: 'assistant',
   378→              content: activeCharacter.greeting,
   379→              timestamp: new Date(),
   380→              characterId: activeCharacter.id,
   381→              characterType: type,
   382→            },
   383→          ];
   384→        }
   385→
   386→        // 4. Update history
   387→        const newHistory = [
   388→          ...state.characterHistory,
   389→          { type, id: character.id, timestamp: new Date() },
   390→        ];
   391→
   392→        set({
   393→          activeCharacter,
   394→          messages,
   395→          characterHistory: newHistory,
   396→          pendingHandoff: null,
   397→          conversationsByCharacter: savedConversations,
   398→        });
   399→      },
   400→
   401→      switchToCoach: (profile) => {
   402→        const coach = getDefaultSupportTeacher();
   403→        get().switchToCharacter(coach, 'coach', profile);
   404→      },
   405→
   406→      switchToMaestro: (maestro, profile) => {
   407→        get().switchToCharacter(maestro, 'maestro', profile);
   408→      },
   409→
   410→      switchToBuddy: (profile) => {
   411→        const buddy = getBuddyForStudent(profile);
   412→        get().switchToCharacter(buddy, 'buddy', profile);
   413→      },
   414→
   415→      goBack: (profile) => {
   416→        const state = get();
   417→        if (state.characterHistory.length <= 1) {
   418→          return false;
   419→        }
   420→
   421→        // Save current before going back
   422→        const savedConversations = saveCurrentConversation(state);
   423→
   424→        const newHistory = state.characterHistory.slice(0, -1);
   425→        const previous = newHistory[newHistory.length - 1];
   426→
   427→        let character: MaestroFull | SupportTeacher | BuddyProfile | undefined;
   428→
   429→        switch (previous.type) {
   430→          case 'maestro':
   431→            character = getMaestroById(previous.id);
   432→            break;
   433→          case 'coach':
   434→            character = getSupportTeacherById(previous.id as 'melissa' | 'roberto');
   435→            break;
   436→          case 'buddy':
   437→            character = getBuddyById(previous.id as BuddyId);
   438→            break;
   439→        }
   440→
   441→        if (!character) {
   442→          return false;
   443→        }
   444→
   445→        const activeCharacter = createActiveCharacter(character, previous.type, profile);
   446→
   447→        // Load that character's messages
   448→        const messages = loadConversationMessages(savedConversations, previous.id);
   449→
   450→        set({
   451→          activeCharacter,
   452→          messages: messages.length > 0 ? messages : [
   453→            {
   454→              id: crypto.randomUUID(),
   455→              role: 'assistant',
   456→              content: activeCharacter.greeting,
   457→              timestamp: new Date(),
   458→              characterId: activeCharacter.id,
   459→              characterType: previous.type,
   460→            },
   461→          ],
   462→          characterHistory: newHistory,
   463→          pendingHandoff: null,
   464→          conversationsByCharacter: savedConversations,
   465→        });
   466→
   467→        return true;
   468→      },
   469→
   470→      suggestHandoff: (suggestion) => {
   471→        set({ pendingHandoff: suggestion });
   472→      },
   473→
   474→      acceptHandoff: (profile) => {
   475→        const state = get();
   476→        if (!state.pendingHandoff) return;
   477→
   478→        const { toCharacter } = state.pendingHandoff;
   479→        get().switchToCharacter(toCharacter.character, toCharacter.type, profile);
   480→      },
   481→
   482→      dismissHandoff: () => {
   483→        set({ pendingHandoff: null });
   484→      },
   485→
   486→      getConversationForCharacter: (characterId) => {
   487→        const state = get();
   488→        return state.conversationsByCharacter[characterId] || null;
   489→      },
   490→
   491→      getAllConversations: () => {
   492→        const state = get();
   493→        return Object.values(state.conversationsByCharacter).sort((a, b) => {
   494→          const aTime = a.lastMessageAt?.getTime() || 0;
   495→          const bTime = b.lastMessageAt?.getTime() || 0;
   496→          return bTime - aTime; // Most recent first
   497→        });
   498→      },
   499→
   500→      reset: () => {
   501→        set({
   502→          mode: 'idle',
   503→          isActive: false,
   504→          activeCharacter: null,
   505→          messages: [],
   506→          pendingHandoff: null,
   507→          conversationsByCharacter: {},
   508→          sessionId: null,
   509→          sessionStartedAt: null,
   510→          characterHistory: [],
   511→        });
   512→      },
   513→    })
   514→);
