   313→function createActiveCharacter(
   314→  character: MaestroFull | SupportTeacher | BuddyProfile,
   315→  type: CharacterType,
   316→  profile: ExtendedStudentProfile
   317→): ActiveCharacter {
   318→  let greeting: string;
   319→  let systemPrompt: string;
   320→  let voiceInstructions: string;
   321→
   322→  if (type === 'buddy') {
   323→    const buddy = character as BuddyProfile;
   324→    greeting = buddy.getGreeting(profile);
   325→    systemPrompt = buddy.getSystemPrompt(profile);
