   327→  } else if (type === 'coach') {
   328→    const coach = character as SupportTeacher;
   329→    greeting = coach.greeting;
   330→    systemPrompt = coach.systemPrompt;
   331→    voiceInstructions = coach.voiceInstructions;
   332→  } else {
   333→    const maestro = character as MaestroFull;
   334→    greeting = maestro.greeting;
   335→    systemPrompt = maestro.systemPrompt;
   336→    voiceInstructions = '';
   337→  }
   338→
   339→  return {
   340→    type,
   341→    id: character.id,
   342→    name: character.name,
   343→    character,
   344→    greeting,
   345→    systemPrompt,
   346→    color: character.color,
   347→    voice: 'voice' in character ? character.voice : 'alloy',
   348→    voiceInstructions,
   349→  };
   350→}
