   352→/**
   353→ * Save current messages to character's conversation bucket.
   354→ */
   355→function saveCurrentConversation(
   356→  state: ConversationFlowState
   357→): Record<string, CharacterConversation> {
   358→  if (!state.activeCharacter || state.messages.length === 0) {
   359→    return state.conversationsByCharacter;
   360→  }
   361→
   362→  const characterId = state.activeCharacter.id;
   363→  const existingConvo = state.conversationsByCharacter[characterId];
   364→
   365→  return {
   366→    ...state.conversationsByCharacter,
   367→    [characterId]: {
   368→      characterId,
   369→      characterType: state.activeCharacter.type,
   370→      characterName: state.activeCharacter.name,
   371→      messages: state.messages,
   372→      lastMessageAt: new Date(),
   373→      conversationId: existingConvo?.conversationId,
   374→    },
   375→  };
   376→}
