          pendingHandoff: null,
        });
      },

      endConversation: () => {
        // Save current conversation before ending
        const state = get();
        const updatedConversations = saveCurrentConversation(state);

        // Stop inactivity monitoring
        if (state.sessionId) {
          inactivityMonitor.stopTracking(state.sessionId);
        }

        set({
          isActive: false,
          mode: 'idle',
          activeCharacter: null,
          messages: [],
          pendingHandoff: null,
